import React, { Component } from "react";

export default class Dashboard extends Component {
  render() {
    return (
      <div className="dashboard">
        <h4 className="revenue-metrics">Revenue metrics</h4>
        <ul className="list">
          <li>Total number of sales</li>
          <li>Cost per acquisition (cost of acquiring a customer)</li>
          <li>
            Revenue on advertising spent (what you earned from what you spent on
            advertising)
          </li>
          <li>Gross profit margin (total revenue minus costs)</li>
          <li>
            Return on investment (what you invest versus what you get back in
            revenue)
          </li>
        </ul>
        <h4 className="conversion-metrics">Conversion metrics</h4>
        <ul className="list">
          <li>Average order value</li>
          <li>
            Shopping cart abandonment rate (how many customers abandon their
            shopping cart before checkout)
          </li>
          <li>
            Email open rate (percentage of subscribers who opened an email)
          </li>
          <li>
            Click-through rate (percentage of subscribers who clicked a link)
          </li>
        </ul>
        <h4 className="experience-metrics">Experience metrics</h4>
        <ul className="list">
          <li>
            Customer retention rate (percentage of customers who become repeat
            customers)
          </li>
          <li>
            Customer lifetime value (revenue earned from a customer during their
            lifetime as your customer)
          </li>
          <li>
            Repeat purchase rate (percentage of purchases made by repeat
            customers)
          </li>
          <li>Return rate (percentage of returned items)</li>
        </ul>
        <h4 className="traffic-metrics">Traffic metrics</h4>
        <ul className="list">
          <li>
            Referral rate (percentage of visitors who came to you by clicking a
            link on another website)
          </li>
          <li>
            Website traffic (how many visitors your website had in a certain
            timeframe)
          </li>
          <li>
            Organic traffic (how many visitors found you through a search
            engine)
          </li>
          <li>
            Traffic sources (how many visitors your website had from different
            channels)
          </li>
        </ul>
      </div>
    );
  }
}
